viewof showCircles = Inputs.toggle({label: "Show equal-distance \"circles\" around A", value: false})









Code
taxicabPlot = {
  const width = 480, height = 480, pad = 30;
  const domain = 7;
  const scale = (width - 2 * pad) / (2 * domain);
  const toSvgX = x =&gt; pad + (x + domain) * scale;
  const toSvgY = y =&gt; height - pad - (y + domain) * scale;

  const svg = d3.create("svg")
      .attr("viewBox", [0, 0, width, height])
      .attr("width", width)
      .attr("height", height)
      .style("font-family", "sans-serif")
      .style("font-size", "11px");

  for (let i = -domain; i &lt;= domain; i++) {
    svg.append("line")
       .attr("x1", toSvgX(i)).attr("x2", toSvgX(i))
       .attr("y1", toSvgY(-domain)).attr("y2", toSvgY(domain))
       .attr("stroke", "#ddd").attr("stroke-width", i === 0 ? 1.5 : 0.5);
    svg.append("line")
       .attr("y1", toSvgY(i)).attr("y2", toSvgY(i))
       .attr("x1", toSvgX(-domain)).attr("x2", toSvgX(domain))
       .attr("stroke", "#ddd").attr("stroke-width", i === 0 ? 1.5 : 0.5);
  }

  const dTaxi = Math.abs(bx) + Math.abs(by);

  if (showCircles && dTaxi &gt; 0) {
    svg.append("circle")
       .attr("cx", toSvgX(0)).attr("cy", toSvgY(0))
       .attr("r", dTaxi * scale)
       .attr("fill", "none").attr("stroke", "#a22c29")
       .attr("stroke-dasharray", "4,3").attr("stroke-width", 1.5);

    const pts = [[dTaxi, 0], [0, dTaxi], [-dTaxi, 0], [0, -dTaxi]]
      .map(([x, y]) =&gt; `${toSvgX(x)},${toSvgY(y)}`).join(" ");
    svg.append("polygon").attr("points", pts)
       .attr("fill", "#b9baa3").attr("fill-opacity", 0.25)
       .attr("stroke", "#556b2f").attr("stroke-width", 1.5);
  }

  svg.append("line")
     .attr("x1", toSvgX(0)).attr("y1", toSvgY(0))
     .attr("x2", toSvgX(bx)).attr("y2", toSvgY(by))
     .attr("stroke", "#a22c29").attr("stroke-width", 2).attr("stroke-dasharray", "6,4");

  svg.append("polyline")
     .attr("points", `${toSvgX(0)},${toSvgY(0)} ${toSvgX(bx)},${toSvgY(0)} ${toSvgX(bx)},${toSvgY(by)}`)
     .attr("fill", "none").attr("stroke", "#2c6ea2").attr("stroke-width", 2.5);

  svg.append("circle").attr("cx", toSvgX(0)).attr("cy", toSvgY(0)).attr("r", 5).attr("fill", "#111");
  svg.append("text").attr("x", toSvgX(0) + 8).attr("y", toSvgY(0) - 8).text("A");

  svg.append("circle").attr("cx", toSvgX(bx)).attr("cy", toSvgY(by)).attr("r", 5).attr("fill", "#2c6ea2");
  svg.append("text").attr("x", toSvgX(bx) + 8).attr("y", toSvgY(by) - 8).text("B");

  return svg.node();
}









Code
md`**Euclidean distance (dashed red line):** ${Math.hypot(bx, by).toFixed(2)}
**Taxicab distance (blue "city block" path):** ${Math.abs(bx) + Math.abs(by)}

${showCircles ? "The dashed red circle is every point at the Euclidean distance you see above from A. The green **diamond** is every point at that *same number* of taxicab blocks from A — under the taxicab metric, that diamond is a perfect \"circle.\"" : ""}`







Every red-dashed line above is the only shortest Euclidean path between A and B. The blue path is just one shortest taxicab path — any staircase of unit right/up steps from A to B has exactly the same taxicab length, since you can’t do better than the total horizontal and vertical distance combined. That’s the same idea driving the poster above: once you replace the notion of “straight line” with a taxicab norm, distances, shortest paths, and even circles change shape — and the research asks how far that idea can be pushed while keeping the space provably hyperbolic.

The grid environment
Blocks recursively refine near a diagonal shock front; blocks intersecting the shock carry up to 5x the baseline workload. An adjacency graph tracks boundary overlap length between neighboring blocks, since that overlap is what drives communication cost.


Code
import numpy as np
import matplotlib.pyplot as plt
import matplotlib.patches as patches

class AMREnvironment:
    def __init__(self, domain_size=16.0, base_block_size=4.0, beta=0.25):
        self.domain_size = domain_size
        self.base_block_size = base_block_size
        self.beta = beta
        self.blocks = []
        self.adj = {}  # block_id -&gt; list of (neighbor_id, overlap_length)

    def generate_grid(self, shock_pos=8.0, shock_angle=np.pi / 4, shock_width=2.5, shock_intensity=5.0):
        self.blocks = []
        self.adj = {}
        cos_a, sin_a = np.cos(shock_angle), np.sin(shock_angle)

        def refine_recursive(x, y, level, size):
            cx, cy = x + size / 2.0, y + size / 2.0
            dist = abs(cx * cos_a + cy * sin_a - shock_pos)
            should_refine = (level &lt; 2) and (dist &lt; shock_width / (level + 1))
            if should_refine:
                half = size / 2.0
                sub_blocks = []
                for dx in [0.0, half]:
                    for dy in [0.0, half]:
                        sub_blocks.extend(refine_recursive(x + dx, y + dy, level + 1, half))
                return sub_blocks
            workload = 1.0
            if dist &lt; shock_width:
                workload = 1.0 + (shock_intensity - 1.0) * (1.0 - dist / shock_width)
            return [{"x": x, "y": y, "level": level, "size": size, "workload": workload}]

        num_base_blocks = int(self.domain_size / self.base_block_size)
        raw_blocks = []
        for i in range(num_base_blocks):
            for j in range(num_base_blocks):
                raw_blocks.extend(
                    refine_recursive(i * self.base_block_size, j * self.base_block_size, 0, self.base_block_size)
                )

        for idx, block in enumerate(raw_blocks):
            block["id"] = idx
            self.blocks.append(block)
            self.adj[idx] = []
        self._compute_adjacencies()

    def _compute_adjacencies(self):
        n = len(self.blocks)
        for i in range(n):
            b1 = self.blocks[i]
            for j in range(i + 1, n):
                b2 = self.blocks[j]
                x_touch = (abs(b1["x"] + b1["size"] - b2["x"]) &lt; 1e-9) or (abs(b2["x"] + b2["size"] - b1["x"]) &lt; 1e-9)
                y_overlap = max(0.0, min(b1["y"] + b1["size"], b2["y"] + b2["size"]) - max(b1["y"], b2["y"]))
                y_touch = (abs(b1["y"] + b1["size"] - b2["y"]) &lt; 1e-9) or (abs(b2["y"] + b2["size"] - b1["y"]) &lt; 1e-9)
                x_overlap = max(0.0, min(b1["x"] + b1["size"], b2["x"] + b2["size"]) - max(b1["x"], b2["x"]))
                overlap = 0.0
                if x_touch and y_overlap &gt; 1e-9:
                    overlap = y_overlap
                elif y_touch and x_overlap &gt; 1e-9:
                    overlap = x_overlap
                if overlap &gt; 0.0:
                    self.adj[b1["id"]].append((b2["id"], overlap))
                    self.adj[b2["id"]].append((b1["id"], overlap))

    def evaluate_assignment(self, assignment, num_processors):
        comp_loads = np.zeros(num_processors)
        comm_costs = np.zeros(num_processors)
        for idx, block in enumerate(self.blocks):
            p = assignment[idx]
            comp_loads[p] += block["workload"]
            for neighbor_id, overlap in self.adj[block["id"]]:
                if p != assignment[neighbor_id]:
                    comm_costs[p] += self.beta * overlap
        total_loads = comp_loads + comm_costs
        mean_comp = np.mean(comp_loads)
        load_imbalance = (np.max(comp_loads) - np.min(comp_loads)) / mean_comp if mean_comp &gt; 0 else 0.0
        return {
            "makespan": np.max(total_loads),
            "comp_makespan": np.max(comp_loads),
            "load_imbalance": load_imbalance,
            "total_comp": np.sum(comp_loads),
            "total_comm": np.sum(comm_costs),
        }
